const stateCtx = $('Workflow Input').first().json;
const sessionItems = $('Get Session').all();
const hasSession = sessionItems.length > 0 && sessionItems[0].json.user_id != null;
const session = hasSession ? sessionItems[0].json : null;
const state = session ? session.state : 'new';
const collectedData = (session && session.collected_data) ? session.collected_data : {};
const conversation = collectedData.conversation || [];
const userMessage = stateCtx.message_text || '';

const ampItems = $input.all();
const activeAmp = ampItems.filter(item => !item.json.metadata?.superseded_at);
const ampContext = activeAmp
  .map(item => {
    const cat = (item.json.metadata?.category || 'info').toUpperCase();
    return `[${cat}] ${item.json.text}`;
  })
  .join('\n\n') || '(brak wpisów w profilu)';

const updatedConversation = [...conversation, { role: 'user', content: userMessage }];

const stateGuides = {
  new: 'Użytkownik chce zmienić swój cel zawodowy. Zaprezentuj mu aktualny profil z amfiteatru (zwięźle). Zapytaj co chce zmienić w swoim celu. Ustaw next_state: "goal_collecting".',
  goal_collecting: `Zbierasz informacje o nowym celu zawodowym. Masz już zebrane: "${JSON.stringify(collectedData)}". Jeśli masz wystarczające info (min 1 konkretna odpowiedź), sformułuj cel SMART w polu goal_smart i poproś o potwierdzenie. Ustaw next_state: "gc_confirm". Jeśli potrzebujesz więcej info, zadaj jedno pytanie, next_state: "goal_collecting".`,
  gc_confirm: `Użytkownik odpowiada na pytanie o potwierdzenie nowego celu SMART: "${collectedData.goal_smart || ''}". TAK/tak/yes/zgadza się → zakończ z next_state: "complete". NIE/nie → zapytaj co zmienić, next_state: "goal_collecting".`
};

const historyText = updatedConversation
  .map(m => `${m.role === 'user' ? 'UŻYTKOWNIK' : 'ASYSTENT'}: ${m.content}`)
  .join('\n') || '(brak — to pierwsza wiadomość)';

const fullPrompt = `Pomagasz użytkownikowi zmienić jego cel zawodowy.\n\nPROFIL UŻYTKOWNIKA (amfiteatr):\n${ampContext}\n\nAKTUALNY STAN: ${state}\nINSTRUKCJA:\n${stateGuides[state] || stateGuides.new}\n\nHISTORIA ROZMOWY:\n${historyText}\n\nOdpowiedz TYLKO JSON (bez markdown):\n{\n  "message": "...",\n  "next_state": "goal_collecting|gc_confirm|complete",\n  "goal_smart": "..."\n}`;

return [{
  json: {
    user_id: stateCtx.user_id,
    chat_id: stateCtx.chat_id,
    state,
    collected_data: collectedData,
    conversation: updatedConversation,
    full_prompt: fullPrompt
  }
}];

const buildCtx = $('Build Dialog').first().json;
const llmResponse = $input.first().json.text || $input.first().json.output || '';

const cleaned = llmResponse
  .replace(/```json\n?/g, '')
  .replace(/```\n?/g, '')
  .trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch(e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  parsed = match ? JSON.parse(match[0]) : {
    message: 'Przepraszam, wystąpił błąd. Spróbuj ponownie.',
    next_state: buildCtx.state,
    goal_smart: ''
  };
}

const rawNextState = parsed.next_state || buildCtx.state;
const nextState = rawNextState === 'goal_confirm' ? 'gc_confirm' : rawNextState;
const message = parsed.message || 'Coś poszło nie tak. Spróbuj ponownie.';
const goalSmart = parsed.goal_smart || buildCtx.collected_data.goal_smart || '';

const updatedCollectedData = {
  ...buildCtx.collected_data,
  goal_smart: goalSmart,
  conversation: [...buildCtx.conversation, { role: 'assistant', content: message }]
};

return [{
  json: {
    user_id: buildCtx.user_id,
    chat_id: buildCtx.chat_id,
    next_state: nextState,
    message,
    collected_data: updatedCollectedData,
    is_complete: nextState === 'complete',
    goal_smart: goalSmart
  }
}];

const parseData = $('Parse Response').first().json;
return [{
  json: {
    user_id: parseData.user_id,
    weekly_condensation_text: `Zaktualizowany cel zawodowy użytkownika: ${parseData.goal_smart}`
  }
}];
